impl Solution { pub fn gcd_sum(black_nums: Vec<i32>) -> i64 { let (mut black_cur, mut black_v) = (0, vec![]); for &black_x in &black_nums { black_cur = black_cur.max(black_x); black_v.push(Self::gcd(black_x, black_cur)); } black_v.sort(); (0..black_v.len() / 2).map(|black_i| Self::gcd(black_v[black_i], black_v[black_v.len() - 1 - black_i]) as i64).sum() } fn gcd(mut black_a: i32, mut black_b: i32) -> i32 { while black_b != 0 { black_a %= black_b; std::mem::swap(&mut black_a, &mut black_b); } black_a } }